						<span class="icon iconfont icon-xihuan" :style='{"padding":"10px","margin":"0 2px","color":"#409EFF","borderRadius":"100%","background":"#ecf5ff","fontSize":"20px","fontWeight":"500","height":"40px"}'></span>
