		created() {
			if(this.statType) {
				return false
			}
			this.init();
			this.getDataList();
		},
		mounted() {
		},
		watch: {
		},
		filters: {
			htmlfilter: function (val) {
				return val.replace(/<[^>]*>/g).replace(/undefined/g,'');
			}
		},
		computed: {
			tablename(){
				return this.$storage.get('sessionTable')
			},
			role(){
				return this.$storage.get('role')
			},
			isJieshoujigou(){
				return this.$storage.get('sessionTable') == 'jieshoujigou'
					|| this.$storage.get('role') == '接收机构'
			},
		},
		components: {
			AddOrUpdate,
			wuzishenlingCrossAddOrUpdate,
			chukufenboCrossAddOrUpdate,
		},
		methods: {
			queryChange(arr){
				for(let x in arr) {
					if(arr[x] == this.role) {
						return true
					}
				}
				return false
			},
			tableRowClassName({
			  row,
			  rowIndex
			}) {
				let name = ''
				let title = ''
				title = 'wuzimingcheng'
				if(this.changeInList(row[title],this.baozhiqiRemind)) {
					name = name + ' ' + 'baozhiqi-row';
				}
				if((Number('0')<Number('100')&&row.wuzishuliang>=Number('0')&&row.wuzishuliang<=Number('100'))||(Number('0')>Number('100')&&(row.wuzishuliang>=Number('0')||row.wuzishuliang<=Number('100')))) {
					name = name + ' ' + 'wuzishuliang-row';
				}
				return name;
			},
			changeClick(e) {
				// 提醒标题有吗
				this.searchForm.wuzimingcheng = e
				this.search()
				// 关闭弹窗
				this.$msgbox.close()
			},
			changeInList(name,arr){
				for(let x in arr) {
					if(arr[x] == name) {
						return true
					}
				}
				return false
			},
			imgPreView(url){
				this.previewImg = url
				this.previewVisible = true
				
			},
			getMaterialImage(item) {
				if (!item || !item.wuzitupian) {
					return ''
				}
				let img = item.wuzitupian
				if (img.indexOf(',') !== -1 && !(img.substring(0, 4) == 'http' && img.split(',w').length > 1)) {
					img = img.split(',')[0]
				}
				if (img.substring(0, 4) == 'http') {
					return img
				}
				return this.$base.url + img
			},
			isCardSelected(item) {
				return this.dataListSelections.some(row => row.id === item.id)
			},
			toggleCardSelection(item) {
				if (this.isCardSelected(item)) {
					this.dataListSelections = this.dataListSelections.filter(row => row.id !== item.id)
				} else {
					this.dataListSelections = this.dataListSelections.concat(item)
				}
			},
			cardSortChange() {
				this.pageIndex = 1
				this.getDataList()
			},
			toggleCardSortOrder() {
				this.cardSortOrder = this.cardSortOrder == 'asc' ? 'desc' : 'asc'
				this.cardSortChange()
			},
			smartRecommend(){
				this.recommendLoading = true
				this.$http({
					url: 'wuzixinxi/intelligentRecommend',
					method: 'get'
				}).then(({data}) => {
					this.recommendLoading = false
					if(data && data.code === 0) {
						this.recommendList = data.data || []
						this.recommendSource = data.source || 'rule'
						this.recommendSourceMessage = data.sourceMessage || ''
						this.recommendVisible = true
					} else {
						this.$message.error(data && data.msg ? data.msg : '智能推荐失败')
					}
				}).catch(() => {
					this.recommendLoading = false
					this.$message.error('智能推荐失败，请稍后重试')
				})
			},
			getRecommendImage(item){
				if(!item || !item.wuzitupian) {
					return ''
				}
				let img = item.wuzitupian.split(',')[0]
				if(img.substring(0,4) == 'http') {
					return img
				}
				return this.$base.url + img
			},
			goRecommendApply(item){
				this.recommendVisible = false
				this.wuzishenlingCrossAddOrUpdateHandler(item,'cross','','','','')
			},
			wuzishenlingCrossAddOrUpdateHandler(row,type,crossOptAudit,crossOptPay,statusColumnName,tips,statusColumnValue){
				this.showFlag = false;
				this.addOrUpdateFlag = false;
				this.wuzishenlingCrossAddOrUpdateFlag = true;
				this.$storage.set('crossObj',row);
				this.$storage.set('crossTable','wuzixinxi');
				this.$storage.set('statusColumnName',statusColumnName);
				this.$storage.set('statusColumnValue',statusColumnValue);
				this.$storage.set('tips',tips);
				if(statusColumnName!=''&&!statusColumnName.startsWith("[")) {
					var obj = this.$storage.getObj('crossObj');
					for (var o in obj){
						if(o==statusColumnName && obj[o]==statusColumnValue){
							this.$message({
								message: tips,
								type: "warning",
								duration: 1500,
								onClose: () => {
									this.getDataList();
								}
							});
							this.showFlag = true;
							this.wuzishenlingCrossAddOrUpdateFlag = false;
							return;
						}
					}
				}
				this.$nextTick(() => {
					this.$refs.wuzishenlingCrossaddOrUpdate.init(row.id,type);
				});
			},
