									h('div', { style: 'text-align: center' }, [
										h('span', null, `包含：`),
										arr
									])
								])
							]),
							showCancelButton: false,
						})
					}
				});
				let urlbaozhiqi = 'wuzixinxi/remind/baozhiqi/2';
				urlbaozhiqi+=`?remindend=5`,

