						const h = this.$createElement;
						var name = data.data
						this.baozhiqiRemind = data.data
						var arr = []
						for(let x=0;x<name.length;x++) {
							arr.push(h('span',{style: 'color: teal;font-weight: bold;cursor: pointer;text-decoration: underline;', on: { click: () => this.changeClick(name[x]) }}, `${name[x]}${(x!=name.length - 1)?'，':''}`))
						}
						this.$msgbox({
							message: h('p', null, [
								h('div', { style: 'text-align: center;font-weight: bold;font-size: 20px;padding: 20px 0' }, `${data.count}条保质期到期预警`),
								h('p', null, [
